import { useState, useEffect } from "react";

function MoviePopup({ movie, onClose, onDelete, onUpdate }) {
    const [isEditing, setIsEditing] = useState(false);
    const [newTitle, setNewTitle] = useState("");

    useEffect(() => {
        if (movie) {
            setNewTitle(movie.title);
            setIsEditing(false);
        }
    }, [movie]);

    if (!movie) return null;

    const handleSave = () => {
        if (newTitle.trim() === "") {
            alert("Title cannot be empty!");
            return;
        }
        onUpdate(movie.id, newTitle);
        setIsEditing(false);
    };

    return (
        <div className="modal" onClick={onClose}>
            <div className="modal-content" onClick={(e) => e.stopPropagation()}>
                <button className="close-x" onClick={onClose} aria-label="Close modal">&times;</button>

                {/* NEW: Image Container for edge-to-edge look */}
                <div className="modal-header-image">
                    <img src={movie.poster} alt={movie.title} />
                    <div className="modal-overlay-bottom"></div>
                </div>

                <div className="modal-body">
                    {isEditing ? (
                        <div className="edit-mode">
                            <input
                                type="text"
                                value={newTitle}
                                onChange={(e) => setNewTitle(e.target.value)}
                                className="modal-edit-input"
                                autoFocus
                            />
                            <div className="modal-buttons">
                                <button className="btn-save" onClick={handleSave}>Save Changes</button>
                                <button className="btn-cancel" onClick={() => setIsEditing(false)}>Cancel</button>
                            </div>
                        </div>
                    ) : (
                        <>
                            <h2>{movie.title}</h2>
                            <div className="modal-buttons">
                                <button className="btn-edit-trigger" onClick={() => setIsEditing(true)}>
                                    ✏️ Edit Title
                                </button>
                                <button className="btn-delete" onClick={() => {
                                    if (window.confirm("Delete this movie?")) {
                                        onDelete(movie.id);
                                        onClose();
                                    }
                                }}>
                                    🗑️ Remove from List
                                </button>
                            </div>
                        </>
                    )}
                </div>
            </div>
        </div>
    );
}

export default MoviePopup;
